import sys

class Solution:
    def heapify(self, heap):
        n = len(heap) - 1
        for i in range(n, -1, -1):
            self.heapify_helper(heap, i)

    def heapify_helper(self, heap, i):
        smallest = i
        left = 2 * i + 1
        right = 2 * i + 2

        if left < len(heap) and heap[left] < heap[smallest]:
            smallest = left
        if right < len(heap) and heap[right] < heap[smallest]:
            smallest = right

        if smallest != i:
            self.swap(heap, i, smallest)
            self.heapify_helper(heap, smallest)

    def swap(self, heap, i, j):
        heap[i], heap[j] = heap[j], heap[i]

    def insert(self, x, heap):
        heap.append(x)
        n = len(heap) - 1
        while n > 0:
            parent = (n - 1) // 2
            if heap[parent] <= heap[n]:
                break
            self.swap(heap, parent, n)
            n = parent

    def removeMin(self, heap):
        if len(heap) == 0:
            return
        if len(heap) == 1:
            return heap.pop(0)
        min_val = heap[0]
        heap[0] = heap.pop()
        self.heapify(heap)
        return min_val

    def removeMax(self, heap):
        if len(heap) == 0:
            return
        if len(heap) == 1:
            return heap.pop(0)
        max_val = heap[-1]
        heap[-1] = heap.pop(0)
        self.heapify(heap)
        return max_val

if __name__ == '__main__':
    solution = Solution()
    n, *nums = map(int, sys.stdin.readline().split())
    solution.insert(0, [])
    for num in nums:
        solution.insert(num, solution.heap)

    print(' '.join(map(str, solution.heap)))

