// -*- coding: utf-8 -*-
#include <iostream>
#include <vector>
using namespace std;

class Solution {
public:
    void insert(int x, vector<int>& heap) {
        heap.push_back(x);
        n = heap.size() - 1;
        while (n > 0) {
            parent = (n - 1) / 2;
            if (heap[parent] <= heap[n]) {
                break;
            }
            swap(heap[parent], heap[n]);
            n = parent;
        }
    }
    int removeMin(vector<int>& heap) {
        if (heap.size() == 0) {
            return -1;
        }
        if (heap.size() == 1) {
            return heap.pop_back();
        }
        int min_val = heap[0];
        heap[0] = heap.back();
        heap.pop_back();
        heapify(heap);
        return min_val;
    }
    int removeMax(vector<int>& heap) {
        if (heap.size() == 0) {
            return -1;
        }
        if (heap.size() == 1) {
            return heap.pop_back();
        }
        int max_val = heap.back();
        heap.back() = heap[0];
        heap.pop_back();
        heapify(heap);
        return max_val;
    }
    void heapify(vector<int>& heap) {
        n = heap.size() - 1;
        for (int i = n; i >= 0; --i) {
            heapify_helper(heap, i);
        }
    }
    void heapify_helper(vector<int>& heap, int i) {
        int smallest = i;
        left = 2 * i + 1;
        right = 2 * i + 2;
        if (left < heap.size() && heap[left] < heap[smallest]) {
            smallest = left;
        }
        if (right < heap.size() && heap[right] < heap[smallest]) {
            smallest = right;
        }
        if (smallest != i) {
            swap(heap[i], heap[smallest]);
            heapify_helper(heap, smallest);
        }
    }
    void swap(vector<int>& heap, int i, int j) {
        int temp = heap[i];
        heap[i] = heap[j];
        heap[j] = temp;
    }
    int n;
};

int main() {
    Solution solution;
    int n;
    cin >> n;
    vector<int> heap;
    while (n--) {
        int x;
        cin >> x;
        solution.insert(x, heap);
    }
    for (int i = 0; i < heap.size(); i++) {
        cout << heap[i] << ' ';
    }
    return 0;
}
